1	interface Item {
2	  name: string;
3	  type: "standard" | "component";
4	  cursed?: boolean;
5	  enchantment?: number;
6	}
7	
8	interface QuoteOptions {
9	  insurance?: boolean;
10	  years?: number;
11	  followUp?: boolean;
12	  fiveG?: boolean;
13	}
14	
15	const DEDUCTIBLE = 100;
16	const INSURANCE_CAP_MULTIPLIER = 2;
17	
18	const getBaseCostByType = (itemType: string): number => {
19	  return itemType === "component" ? 5 : 10;
20	};
21	
22	const calculateItemPremium = (item: Item): number => {
23	  let premium = getBaseCostByType(item.type);
24	  if (item.cursed) {
25	    premium += premium * 0.5;
26	  }
27	  if (item.enchantment !== undefined && item.enchantment >= 5) {
28	    premium += premium * 0.3;
29	  }
30	  return premium;
31	};
32	
33	const applyPercentageModifier = (amount: number, multiplier: number): number => {
34	  return amount + amount * multiplier;
35	};
36	
37	const applyInsuranceModifier = (premium: number, hasInsurance: boolean): number => {
38	  return hasInsurance ? applyPercentageModifier(premium, 0.1) : premium;
39	};
40	
41	const applyLoyaltyModifier = (premium: number, years?: number): number => {
42	  return years !== undefined && years >= 2 ? applyPercentageModifier(premium, -0.2) : premium;
43	};
44	
45	const applyFollowUpModifier = (premium: number, hasFollowUp: boolean): number => {
46	  return hasFollowUp ? applyPercentageModifier(premium, -0.15) : premium;
47	};
48	
49	const roundPremiumInMhpcosFavor = (premium: number, hasInsuranceAndYears: boolean): number => {
50	  return hasInsuranceAndYears ? Math.floor(premium) + 1 : premium;
51	};
52	
53	export function quote(items: Item[], options: QuoteOptions = {}): number {
54	  let total = 0;
55	  for (const item of items) {
56	    total += calculateItemPremium(item);
57	  }
58	  total = applyInsuranceModifier(total, options.insurance === true);
59	  total = applyLoyaltyModifier(total, options.years);
60	  total = applyFollowUpModifier(total, options.followUp === true);
61	  if (options.fiveG === true) {
62	    total += 1;
63	  }
64	  const hasInsuranceAndYears = options.insurance === true && options.years !== undefined;
65	  total = roundPremiumInMhpcosFavor(total, hasInsuranceAndYears);
66	  return total;
67	}
68	
69	export function claim(itemValue: number, insuredAmount: number, damageValue: number, enchantment?: number, isDragon?: boolean): number {
70	  const afterDeductible = damageValue - DEDUCTIBLE;
71	  if (isDragon) {
72	    return afterDeductible;
73	  }
74	  if (enchantment !== undefined && enchantment >= 8) {
75	    return afterDeductible * 0.5;
76	  }
77	  const cap = INSURANCE_CAP_MULTIPLIER * insuredAmount;
78	  if (afterDeductible <= cap) {
79	    return afterDeductible - insuredAmount;
80	  }
81	  return cap - DEDUCTIBLE;
82	}
